#[test]
fn table_style_bold_alone_resolves_on_single_level() {
    // ISO 29500-1 §17.7.3: a toggle true at exactly one hierarchy level (the
    // table style) is an odd count, so effective bold is ON. Positive control
    // for the XOR rule. Daily-falsifiable post-condition: opens-clean.
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr/></w:rPrDefault><w:pPrDefault><w:pPr/></w:pPrDefault></w:docDefaults><w:style w:type="table" w:styleId="BoldTable"><w:name w:val="Bold Table"/><w:rPr><w:b/></w:rPr></w:style></w:styles>"#;
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="BoldTable"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:r><w:t>cell text</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p><w:r><w:t>after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.7.3 — a bold table style on a plain cell paragraph is \
         valid WordprocessingML; Word opens it without repair. Validator issues: {:?}",
        report.issues
    );
}

#[test]
fn toggle_xor_resolution_never_deletes_run_text() {
    // ISO 29500-1 §17.7.3: toggle XOR is appearance-only ("combined by a
    // Boolean XOR"); it never removes content. Accept and reject must both
    // reproduce the cell run text verbatim regardless of how bold resolves.
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr/></w:rPrDefault><w:pPrDefault><w:pPr/></w:pPrDefault></w:docDefaults><w:style w:type="table" w:styleId="BoldTable"><w:name w:val="Bold Table"/><w:rPr><w:b/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="BoldPara"><w:name w:val="Bold Para"/><w:rPr><w:b/></w:rPr></w:style></w:styles>"#;
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="BoldTable"/></w:tblPr><w:tblGrid><w:gridCol w:w="5000"/></w:tblGrid><w:tr><w:tc><w:tcPr><w:tcW w:w="5000" w:type="dxa"/></w:tcPr><w:p><w:pPr><w:pStyle w:val="BoldPara"/></w:pPr><w:r><w:t>keepme</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    assert_eq!(
        accept_text(&b).trim(),
        "keepme",
        "ISO 29500-1 §17.7.3 — toggle XOR is appearance-only; accept-all must \
         reproduce the cell run text verbatim (no content loss)."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "keepme",
        "ISO 29500-1 §17.7.3 — toggle XOR is appearance-only; reject-all must \
         reproduce the cell run text verbatim (no content loss)."
    );
    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.7.3 — the construct is valid WordprocessingML; Word \
         opens it without repair. Validator issues: {:?}",
        report.issues
    );
}

#[test]
fn xor_table_para_char_three_levels_opens_clean_text_survives() {
    // ISO/IEC 29500-1 §17.7.3 + ECMA-376 §17.3.2.1: bold true at para and char
    // style levels; XOR is a render/effective-value rule, so the falsifiable
    // daily post-conditions are opens-clean and text-survival on accept/reject.
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="ParaBold"><w:name w:val="Para Bold"/><w:rPr><w:b/></w:rPr></w:style><w:style w:type="character" w:styleId="CharBold"><w:name w:val="Char Bold"/><w:rPr><w:b/></w:rPr></w:style></w:styles>"#;
    let body = r#"<w:p><w:pPr><w:pStyle w:val="ParaBold"/></w:pPr><w:r><w:rPr><w:rStyle w:val="CharBold"/></w:rPr><w:t>XOR three levels</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO/IEC 29500-1 §17.7.3 — XOR across para/char style levels is a \
         legitimate resolution path; the document is schema-valid and Word opens \
         it without repair. Validator issues: {:?}",
        report.issues
    );
    assert_eq!(
        accept_text(&b).trim(),
        "XOR three levels",
        "ISO/IEC 29500-1 §17.7.3, ECMA-376 §17.3.2.1 — bold is a toggle \
         (appearance) property; resolving it across levels changes only display, \
         so accept-all reproduces the original text verbatim."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "XOR three levels",
        "ISO/IEC 29500-1 §17.7.3 — no tracked changes present; toggle resolution \
         is appearance-only, so reject-all reproduces the original text verbatim."
    );
}

#[test]
fn missing_toggle_level_falls_to_docdefault_not_ecma_default() {
    // MS-OI29500 §2.1.230 + ISO/IEC 29500-1 §17.7.3 / §17.7.5: a style chain
    // that never sets bold, under docDefaults bold=on. Word uses the
    // document-defaults value for the unset level. Consumption surface =>
    // opens-clean + text-survival.
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:docDefaults><w:rPrDefault><w:rPr><w:b/></w:rPr></w:rPrDefault></w:docDefaults><w:style w:type="paragraph" w:styleId="BaseNoBold"><w:name w:val="Base No Bold"/><w:rPr><w:i/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="NoBoldChain"><w:name w:val="No Bold Chain"/><w:basedOn w:val="BaseNoBold"/></w:style></w:styles>"#;
    let body = r#"<w:p><w:pPr><w:pStyle w:val="NoBoldChain"/></w:pPr><w:r><w:t>default from docDefaults</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "MS-OI29500 §2.1.230, ISO/IEC 29500-1 §17.7.3/§17.7.5 — a style chain \
         that never sets bold with docDefaults bold=on is schema-valid; Word \
         opens it without repair. Validator issues: {:?}",
        report.issues
    );
    assert_eq!(
        accept_text(&b).trim(),
        "default from docDefaults",
        "MS-OI29500 §2.1.230 — whether bold is supplied by docDefaults is an \
         appearance decision; it cannot add/remove run text, so accept-all \
         reproduces the text verbatim."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "default from docDefaults",
        "MS-OI29500 §2.1.230, ISO/IEC 29500-1 §17.7.3 — no tracked changes; \
         toggle resolution is appearance-only, so reject-all reproduces the \
         original text verbatim."
    );
}

#[test]
fn direct_toggle_wins_over_multilevel_xor_no_combination() {
    // ISO/IEC 29500-1 §17.7.3: direct formatting short-circuits the toggle
    // combination algorithm. A run with direct bold=false under bold-on para +
    // char styles uses the direct value; consumption => opens-clean + text.
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="ParaBoldOn"><w:name w:val="Para Bold On"/><w:rPr><w:b/></w:rPr></w:style><w:style w:type="character" w:styleId="CharBoldOn"><w:name w:val="Char Bold On"/><w:rPr><w:b/></w:rPr></w:style></w:styles>"#;
    let body = r#"<w:p><w:pPr><w:pStyle w:val="ParaBoldOn"/></w:pPr><w:r><w:rPr><w:rStyle w:val="CharBoldOn"/><w:b w:val="false"/></w:rPr><w:t>direct beats xor</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO/IEC 29500-1 §17.7.3 — a run with direct bold=off over bold-on \
         styles is schema-valid; Word uses the direct value and opens it without \
         repair. Validator issues: {:?}",
        report.issues
    );
    assert_eq!(
        accept_text(&b).trim(),
        "direct beats xor",
        "ISO/IEC 29500-1 §17.7.3 — direct toggle resolution is appearance-only; \
         it cannot add/remove run content, so accept-all reproduces the text."
    );
}

#[test]
fn nontoggle_color_last_value_wins_not_xor() {
    // ISO/IEC 29500-1 §17.7.3: color is NOT a toggle property; it resolves by
    // last-value-wins across the hierarchy, never XOR. Daily-falsifiable
    // consumption post-condition: opens-clean (two color decls is valid).
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="ParaRed"><w:name w:val="Para Red"/><w:rPr><w:color w:val="FF0000"/></w:rPr></w:style><w:style w:type="character" w:styleId="CharBlue"><w:name w:val="Char Blue"/><w:rPr><w:color w:val="0000FF"/></w:rPr></w:style></w:styles>"#;
    let body = r#"<w:p><w:pPr><w:pStyle w:val="ParaRed"/></w:pPr><w:r><w:rPr><w:rStyle w:val="CharBlue"/></w:rPr><w:t>color last value wins</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO/IEC 29500-1 §17.7.3 — two color declarations at different style \
         levels is schema-valid and Word resolves it by last-value; Word opens \
         it without repair. Validator issues: {:?}",
        report.issues
    );
}

#[test]
fn bold_toggle_on_tracked_inserted_run_accept_keeps_reject_drops() {
    // ISO/IEC 29500-1 §17.7.3 + §17.13.5: bold is an appearance toggle
    // orthogonal to tracked-change accept/reject (which acts on content).
    // accept-all keeps the inserted (bold) text; reject-all removes it.
    let body = r#"<w:p><w:r><w:t xml:space="preserve">base </w:t></w:r><w:ins w:id="1" w:author="A" w:date="2026-06-01T00:00:00Z"><w:r><w:rPr><w:b/></w:rPr><w:t>added</w:t></w:r></w:ins></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "base added",
        "ISO/IEC 29500-1 §17.13.5 (+ §17.7.3) — accept-all keeps inserted \
         content; the bold toggle is appearance-only and does not affect which \
         text is retained."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "base",
        "ISO/IEC 29500-1 §17.13.5 (+ §17.7.3) — reject-all removes inserted \
         content regardless of any appearance toggle; only the base text remains \
         ('base ' trims to 'base')."
    );
    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO/IEC 29500-1 §17.13.5 — a bold run inside a w:ins is schema-valid \
         tracked-change markup; Word opens it without repair. Validator issues: {:?}",
        report.issues
    );
}

#[test]
fn toggle_xor_table_plus_para_levels_two_true_resolves_off() {
    // ISO 29500-1 / ECMA-376 §17.7.3 + ECMA-376 §17.3.2.1: bold true at table
    // AND paragraph style levels = even count => effective OFF. The worked
    // §17.7.3 example. Daily post-conditions: opens-clean + content survival.
    // (oracle: acceptTextEquals "cell\n\nafter" — effective OFF is the oracle.)
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="table" w:styleId="BoldTable"><w:name w:val="Bold Table"/><w:rPr><w:b/></w:rPr></w:style><w:style w:type="paragraph" w:styleId="BoldPara"><w:name w:val="Bold Para"/><w:rPr><w:b/></w:rPr></w:style></w:styles>"#;
    let body = r#"<w:tbl><w:tblPr><w:tblStyle w:val="BoldTable"/></w:tblPr><w:tr><w:tc><w:tcPr/><w:p><w:pPr><w:pStyle w:val="BoldPara"/></w:pPr><w:r><w:t>cell</w:t></w:r></w:p></w:tc></w:tr></w:tbl><w:p><w:r><w:t>after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    let report = opens_clean(&b);
    assert!(
        report.ok,
        "ISO 29500-1 §17.7.3 — table-style bold + paragraph-style bold is the \
         canonical worked example and is schema-valid; Word opens it without \
         repair. Validator issues: {:?}",
        report.issues
    );
    assert_eq!(
        accept_text(&b).trim(),
        "cell\n\nafter",
        "ISO 29500-1 §17.7.3, ECMA-376 §17.3.2.1 — bold is appearance only; \
         XOR-resolving it to OFF must never delete run text. Accept-all must \
         preserve 'cell' and 'after'."
    );
}

